                     <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Documento</label\\r\\n                                >\\r\\n                                <el-input\\r\\n                                    class=\\\"to_left\\\"\\r\\n                                    style=\\\"width:100%;\\\"\\r\\n                                    v-model=\\\"documentNumber\\\"\\r\\n                                    @input=\\\"closeProperty\\\"\\r\\n                                    :controls=\\\"false\\\"\\r\\n                                >\\r\\n                                    <el-button\\r\\n                                        v-if=\\\"\\r\\n                                            form.identity_document_type_id ==\\r\\n                                                1 ||\\r\\n                                                form.identity_document_type_id ==\\r\\n                                                    6\\r\\n                                        \\\"\\r\\n                                        slot=\\\"append\\\"\\r\\n                                        :loading=\\\"loading_search\\\"\\r\\n                                        icon=\\\"el-icon-search\\\"\\r\\n                                        @click.prevent=\\\"searchCustomer\\\"\\r\\n                                    ></el-button>\\r\\n                                </el-input>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Nombres</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form.name\\\"> </el-input>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div\\r\\n                            class=\\\"row mt-2\\\"\\r\\n                            v-if=\\\"form.state && form.condition\\\"\\r\\n                        >\\r\\n                            <div class=\\\"col-md-6 col-12\\\"></div>\\r\\n                            <div class=\\\"col-md-3 col-12\\\">\\r\\n                                <el-alert\\r\\n                                    :title=\\\"form.state\\\"\\r\\n                                    :type=\\\"\\r\\n                                        `${\\r\\n                                            form.state == 'ACTIVO'\\r\\n                                                ? 'success'\\r\\n                                                : 'error'\\r\\n                                        }`\\r\\n                                    \\\"\\r\\n                                >\\r\\n                                </el-alert>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-3\\\">\\r\\n                                <el-alert\\r\\n                                    :title=\\\"form.condition\\\"\\r\\n                                    :type=\\\"\\r\\n                                        `${\\r\\n                                            form.condition == 'HABIDO'\\r\\n                                                ? 'success'\\r\\n                                                : 'error'\\r\\n                                        }`\\r\\n                                    \\\"\\r\\n                                >\\r\\n                                </el-alert>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row mt-2\\\">\\r\\n                            <div class=\\\"col-md-4\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{ 'has-danger': errors.country_id }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\">País</label>\\r\\n                                    <el-select\\r\\n                                        v-model=\\\"form.country_id\\\"\\r\\n                                        filterable\\r\\n                                        dusk=\\\"country_id\\\"\\r\\n                                        disabled\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in countries\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.country_id\\\"\\r\\n                                        v-text=\\\"errors.country_id[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-4\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{\\r\\n                                        'has-danger': errors.department_id\\r\\n                                    }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\"\\r\\n                                        >Departamento</label\\r\\n                                    >\\r\\n                                    <el-select\\r\\n                                        v-model=\\\"form.department_id\\\"\\r\\n                                        filterable\\r\\n                                        @change=\\\"filterProvince\\\"\\r\\n                                        popper-class=\\\"el-select-departments\\\"\\r\\n                                        dusk=\\\"department_id\\\"\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in departments\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.department_id\\\"\\r\\n                                        v-text=\\\"errors.department_id[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-4\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{\\r\\n                                        'has-danger': errors.province_id\\r\\n                                    }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\"\\r\\n                                        >Provincia</label\\r\\n                                    >\\r\\n                                    <el-select\\r\\n                                        v-model=\\\"form.province_id\\\"\\r\\n                                        filterable\\r\\n                                        @change=\\\"filterDistrict\\\"\\r\\n                                        popper-class=\\\"el-select-provinces\\\"\\r\\n                                        dusk=\\\"province_id\\\"\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in provinces\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.province_id\\\"\\r\\n                                        v-text=\\\"errors.province_id[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row\\\">\\r\\n                            <div class=\\\"col-md-4\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{\\r\\n                                        'has-danger': errors.district_id\\r\\n                                    }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\"\\r\\n                                        >Distrito</label\\r\\n                                    >\\r\\n                                    <el-select\\r\\n                                        @change=\\\"updateAll\\\"\\r\\n                                        v-model=\\\"form.district_id\\\"\\r\\n                                        filterable\\r\\n                                        popper-class=\\\"el-select-districts\\\"\\r\\n                                        dusk=\\\"district_id\\\"\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in districts\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.district_id\\\"\\r\\n                                        v-text=\\\"errors.district_id[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-8\\\">\\r\\n                                <div\\r\\n                                    class=\\\"form-group\\\"\\r\\n                                    :class=\\\"{ 'has-danger': errors.address }\\\"\\r\\n                                >\\r\\n                                    <label class=\\\"control-label\\\"\\r\\n                                        >Dirección</label\\r\\n                                    >\\r\\n                                    <el-input\\r\\n                                        v-model=\\\"form.address\\\"\\r\\n                                        dusk=\\\"address\\\"\\r\\n                                    >\\r\\n                                        <i\\r\\n                                            slot=\\\"prefix\\\"\\r\\n                                            class=\\\"el-icon-edit-outline\\\"\\r\\n                                        ></i\\r\\n                                    ></el-input>\\r\\n                                    <small\\r\\n                                        class=\\\"text-danger\\\"\\r\\n                                        v-if=\\\"errors.address\\\"\\r\\n                                        v-text=\\\"errors.address[0]\\\"\\r\\n                                    ></small>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row\\\">\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Teléfono</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form.phone\\\"> </el-input>\\r\\n                            </div>\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Correo</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form.email\\\"> </el-input>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"row mt-2\\\">\\r\\n                            <div class=\\\"col-md-6 col-12\\\">\\r\\n                                <label for=\\\"number\\\" class=\\\"control-label\\\"\\r\\n                                    >Teléfono secundario</label\\r\\n                                >\\r\\n                                <el-input v-model=\\\"form.extra_phone\\\">\\r\\n                                </el-input>\\r\\n                            </div>\\r\